(phrase, key) => {
  const { a, b } = key;
  const m = 26;
  if (gcd(a, m) !== 1) throw new Error("a and m must be coprime");
  const cleaned = phrase.toLowerCase().replace(/[^a-z0-9]/g, "");
  let cipher = "";
  for (const ch of cleaned) {
    if (ch >= "0" && ch <= "9") {
      cipher += ch;
    } else {
      const i = ch.charCodeAt(0) - 97;
      cipher += String.fromCharCode(((a * i + b) % m + m) % m + 97);
    }
  }
