const _solve = function solve() {
  return (puzzle) => {
    const [left, right] = puzzle.split("=").map(s => s.trim());
    const leftWords = left.split("+").map(s => s.trim());
    const rightWord = right.trim();
    const allWords = [...leftWords, rightWord];
    const allLetters = [...new Set(allWords.join(""))];
    const leadingLetters = new Set(allWords.map(w => w[0]));
    const n = allLetters.length;

    // Compute coefficient for each letter: left words add, right word subtracts
    const coeffs = new Map();
    for (const l of allLetters) coeffs.set(l, 0);
    for (const word of leftWords) {
      for (let i = 0; i < word.length; i++) {
        coeffs.set(word[i], coeffs.get(word[i]) + 10 ** (word.length - 1 - i));
      }
    }
    for (let i = 0; i < rightWord.length; i++) {
      coeffs.set(rightWord[i], coeffs.get(rightWord[i]) - 10 ** (rightWord.length - 1 - i));
    }

    // Sort letters by absolute coefficient descending for better pruning
    const sorted = [...allLetters].sort((a, b) => Math.abs(coeffs.get(b)) - Math.abs(coeffs.get(a)));

    const mapping = {};
    const used = new Uint8Array(10);

    function search(idx, sum) {
      if (idx === n) return sum === 0 ? { ...mapping } : null;

      const letter = sorted[idx];
      const c = coeffs.get(letter);
      const lo = leadingLetters.has(letter) ? 1 : 0;

      for (let d = lo; d <= 9; d++) {
        if (used[d]) continue;
        mapping[letter] = d;
        used[d] = 1;
        const result = search(idx + 1, sum + c * d);
        if (result) return result;
        used[d] = 0;
      }
      delete mapping[letter];
      return null;
    }

    return search(0, 0);
  };
};

