          if (rollIdx >= this.rolls.length) {
            // Second roll position after strike — any 0–10
            return;
          }
          const second = this.rolls[rollIdx];
          rollIdx++;
          if (rollIdx >= this.rolls.length) {
            // Third roll position
            if (second !== 10 && second + pins > 10) {
              throw new Error("Pin count exceeds pins on the lane");
            }
            return;
