const _ComplexNumber = function ComplexNumber(){
  class ComplexNumber {
    constructor(real = 0, imag = 0) {
      this._real = real;
      this._imag = imag;
    }

    get real() {
      return this._real;
    }

    get imag() {
      return this._imag;
    }

    add(other) {
      return new ComplexNumber(this._real + other._real, this._imag + other._imag);
    }

    sub(other) {
      return new ComplexNumber(this._real - other._real, this._imag - other._imag);
    }

    mul(other) {
      return new ComplexNumber(
        this._real * other._real - this._imag * other._imag,
        this._imag * other._real + this._real * other._imag
      );
    }

    div(other) {
      const d = other._real * other._real + other._imag * other._imag;
      return new ComplexNumber(
        (this._real * other._real + this._imag * other._imag) / d,
        (this._imag * other._real - this._real * other._imag) / d
      );
    }

    get abs() {
      return Math.sqrt(this._real * this._real + this._imag * this._imag);
    }

    get conj() {
      return new ComplexNumber(this._real, -this._imag);
    }

    get exp() {
      return new ComplexNumber(
        Math.exp(this._real) * Math.cos(this._imag),
        Math.exp(this._real) * Math.sin(this._imag)
      );
    }
  }
  return ComplexNumber;
};

