        if (!user.owed_by) user.owed_by = {};
        this._recalcBalance(user);
      }
    }

    _recalcBalance(user) {
      const owedByTotal = Object.values(user.owed_by).reduce((s, v) => s + v, 0);
      const owesTotal = Object.values(user.owes).reduce((s, v) => s + v, 0);
      user.balance = Math.round((owedByTotal - owesTotal) * 100) / 100;
