          const params = new URLSearchParams(url.slice(qIndex + 1));
          const names = params.get('users').split(',');
          users = names.map(n => this._copyUser(this._findUser(n)));
        } else {
          users = this.db.users.map(u => this._copyUser(u));
        }
        return { users: this._sortedUsers(users) };
      }
    }

    post(url, payload) {
