  // Pets:    dog=0, snail=1, fox=2, horse=3, zebra=4
  // Drinks:  coffee=0, tea=1, milk=2, OJ=3, water=4
  // Hobbies: dancing=0, painting=1, reading=2, football=3, chess=4

  const NAMES = ['Englishman','Spaniard','Ukrainian','Norwegian','Japanese'];

  function perms(arr){
    if(arr.length<=1) return [arr];
    const res=[];
    for(let i=0;i<arr.length;i++){
      const rest=[...arr.slice(0,i),...arr.slice(i+1)];
      for(const p of perms(rest)) res.push([arr[i],...p]);
    }
    return res;
