    // 6. green(1) immediately right of ivory(2)
    if(c.indexOf(1)!==c.indexOf(2)+1) continue;
    for(const n of P){
      // 10. Norwegian(3) in house 0
      if(n[0]!==3) continue;
      // 2. Englishman(0) in red(0) house
      if(!sameHouse(c,n,0,0)) continue;
      // 15. Norwegian next to blue(4) → house 1 is blue
      if(c[1]!==4) continue;
      for(const pe of P){
        // 3. Spaniard(1) owns dog(0)
        if(!sameHouse(n,pe,1,0)) continue;
        for(const d of P){
          // 4. green(1) drinks coffee(0)
          if(!sameHouse(c,d,1,0)) continue;
          // 5. Ukrainian(2) drinks tea(1)
          if(!sameHouse(n,d,2,1)) continue;
          // 9. house 2 drinks milk(2)
          if(d[2]!==2) continue;
          for(const ho of P){
            // 7. snail(1) dances(0)
            if(!sameHouse(pe,ho,1,0)) continue;
            // 8. yellow(3) is painter(1)
            if(!sameHouse(c,ho,3,1)) continue;
            // 11. reading(2) next to fox(2)
            if(!adjacent(ho,pe,2,2)) continue;
            // 12. painter(1) next to horse(3)
            if(!adjacent(ho,pe,1,3)) continue;
            // 13. football(3) drinks OJ(3)
            if(!sameHouse(ho,d,3,3)) continue;
            // 14. Japanese(4) plays chess(4)
            if(!sameHouse(n,ho,4,4)) continue;

            const waterHouse = d.indexOf(4);
            const zebraHouse = pe.indexOf(4);
            result = {
              waterDrinker: NAMES[n[waterHouse]],
              zebraOwner: NAMES[n[zebraHouse]]
            };
            break outer;
          }
        }
      }
    }
  }

  class ZebraPuzzle {
    constructor(){}
    waterDrinker(){ return result.waterDrinker; }
    zebraOwner(){ return result.zebraOwner; }
  }
  return ZebraPuzzle;
};

